  seoul:        { flag:"🇰🇷", ko:"역이민·귀환 동포", en:"Returning Diaspora",  descKo:"다시 서울에서, 새롭게 시작하는 일상",  descEn:"Back in Seoul, starting a new chapter of life",   color:"#DC2626" },
