/* ─────────────────────────────────────────
   VIRAL: 공유 섹션 — 카카오·문자·SNS·WhatsApp·이메일·복사
   스크린샷 디자인: 대형 노란 버튼 + 3개 보조 버튼
───────────────────────────────────────── */
function GrowthShareSection({ lang }: { lang: string }) {
  const ko = lang === "ko";
  const cityConfig = useCityConfig();
  const cityNameKo = cityConfig.nameKo;
  const cityNameEn = cityConfig.nameEn;
  const citySlug   = cityConfig.slug;

  const shareUrl   = `https://hebronguide.com/${citySlug}/`;
  const shareTitle = ko
    ? `${cityNameKo} 한인 정착 가이드 — HebronGuide`
    : `${cityNameEn} Korean Settlement Guide — HebronGuide`;
  const shareText  = ko
    ? `${cityNameKo}에 새로 오신 한인분들께 꼭 필요한 정착 앱이에요. 교회·맛집·정착 정보 한 곳에서 무료로!`
    : `The essential free app for Koreans arriving in ${cityNameEn}. Church, food & settlement info — free!`;

  const [copied, setCopied] = useState(false);

  /* 네이티브 공유 (Web Share API) — 카카오·문자·SNS 시스템 시트 */
  const doNativeShare = () => {
    if (navigator.share) {
      navigator.share({ title: shareTitle, text: shareText, url: shareUrl }).catch(() => {});
    } else {
      /* 데스크톱 폴백 → 클립보드 */
      navigator.clipboard?.writeText(`${shareText}\n${shareUrl}`)
        .then(() => { setCopied(true); setTimeout(() => setCopied(false), 2500); });
    }
  };

  /* WhatsApp */
  const doWhatsApp = () => {
    window.open(`https://wa.me/?text=${encodeURIComponent(`${shareText}\n${shareUrl}`)}`, "_blank");
  };

  /* 이메일 */
  const doEmail = () => {
    window.open(
      `mailto:?subject=${encodeURIComponent(shareTitle)}&body=${encodeURIComponent(`${shareText}\n\n${shareUrl}`)}`,
      "_blank"
    );
  };

  /* 링크 복사 */
  const doCopy = () => {
    navigator.clipboard?.writeText(shareUrl)
      .then(() => { setCopied(true); setTimeout(() => setCopied(false), 2500); });
  };

  const btnBase: React.CSSProperties = {
    flex: 1, border: "1px solid rgba(255,255,255,0.13)",
    borderRadius: 12, padding: "11px 6px", cursor: "pointer",
    display: "flex", flexDirection: "column", alignItems: "center", gap: 4,
    background: "rgba(255,255,255,0.07)", transition: "background 0.15s",
  };

  return (
    <div style={{ margin: "12px 16px 0" }}>
      {/* ── 큰 노란 공유 버튼 ── */}
      {/* 카카오톡으로 공유하기 버튼 */}
      <button
        onClick={doNativeShare}
        style={{
          width: "100%", padding: "15px 16px", marginBottom: 12,
          background: "#FEE500", border: "none", borderRadius: 14, cursor: "pointer",
          display: "flex", alignItems: "center", justifyContent: "center", gap: 10,
          boxShadow: "0 4px 16px rgba(254,229,0,0.28)",
          fontFamily: "'Noto Sans KR',Manrope,sans-serif", fontWeight: 800, fontSize: 15, color: "#1a1200",
        }}>
        <span style={{ fontSize: 20 }}>📱</span>
        {ko ? "카카오톡으로 공유하기" : "Share via KakaoTalk"}
      </button>

      {/* 카카오 채널 등록 안내 */}
      <a href="https://pf.kakao.com/_dxdxlbX" target="_blank" rel="noopener noreferrer" style={{ textDecoration: "none", display: "block" }}>
        <div style={{
          display: "flex", alignItems: "center", justifyContent: "space-between",
          padding: "10px 14px",
          background: "#3C2A00",
          borderRadius: 12, gap: 8,
        }}>
          <span style={{ fontSize: 12.5, fontWeight: 600, color: "#FEE500", fontFamily: "'Noto Sans KR',sans-serif", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>
            💬 {ko ? "문의·수정 요청 → 카카오톡 채널" : "Contact via KakaoTalk Channel"}
          </span>
          <span style={{ fontSize: 11.5, fontWeight: 800, color: "#3C2A00", background: "#FEE500", borderRadius: 7, padding: "3px 9px", whiteSpace: "nowrap", fontFamily: "Manrope,sans-serif", flexShrink: 0 }}>
            {ko ? "채널 추가" : "Follow"}
          </span>
        </div>
      </a>

      {/* 🎵 오늘의 음악 — Spotify · Bloom Again Music */}
      <button
        onClick={() => activateMusic()}
        style={{
          width: "100%", marginTop: 10, padding: 0,
          background: "none", border: "none", cursor: "pointer", textAlign: "left",
        }}
      >
        <div style={{
          borderRadius: 14, overflow: "hidden",
          border: "1px solid rgba(29,185,84,0.3)",
          background: "linear-gradient(135deg, #0d1f0d 0%, #0d1117 100%)",
          display: "flex", alignItems: "center", gap: 14, padding: "12px 14px",
        }}>
          {/* Spotify 로고 영역 */}
          <div style={{
            width: 48, height: 48, borderRadius: 12, flexShrink: 0,
            background: "#1DB954",
            display: "flex", alignItems: "center", justifyContent: "center",
            boxShadow: "0 4px 16px rgba(29,185,84,0.35)",
          }}>
            <span style={{ fontSize: 22 }}>🎵</span>
          </div>
          <div style={{ flex: 1, minWidth: 0 }}>
            <div style={{ fontSize: 11, fontWeight: 700, color: "#1DB954", fontFamily: "Manrope,sans-serif", marginBottom: 3, letterSpacing: ".04em" }}>
              {ko ? "🎵 음악 듣기 — 탭 이동해도 계속 재생" : "🎵 Music — plays while you browse"}
            </div>
            <div style={{ fontSize: 13, fontWeight: 800, color: "#ECFDF5", fontFamily: "Manrope,sans-serif", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>
              Bloom Again Music
            </div>
            <div style={{ fontSize: 10.5, color: "rgba(236,253,245,0.5)", fontFamily: "Manrope,sans-serif", marginTop: 2 }}>
              Spotify · Spring Café Romance 외
            </div>
          </div>
          <div style={{ fontSize: 11, fontWeight: 700, color: "rgba(29,185,84,0.8)", fontFamily: "Manrope,sans-serif", flexShrink: 0 }}>
            ▶ 열기
          </div>
        </div>
      </button>

    </div>
  );
}

/* ─────────────────────────────────────────
   PWA 설치 가이드 배너 — iOS/Android 맞춤 안내
   "앱처럼 홈 화면에 추가하는 방법" (3단계)
───────────────────────────────────────── */
function PWAInstallGuideBanner({ lang }: { lang: string }) {
  const ko = lang === "ko";
  const [show, setShow] = useState(false);
  const [expanded, setExpanded] = useState(false);

  useEffect(() => {
    // 이미 standalone(설치됨) 이면 숨김
    const isStandalone = window.matchMedia("(display-mode: standalone)").matches
      || (navigator as unknown as { standalone?: boolean }).standalone === true;
    if (isStandalone) return;
    // 이미 dismissed 했으면 숨김
    if (localStorage.getItem("hg_pwa_dismissed")) return;
    // 모바일만
    if (!/Mobi|Android|iPhone|iPad/i.test(navigator.userAgent)) return;
    // 3초 후 표시
    const t = setTimeout(() => setShow(true), 3000);
    return () => clearTimeout(t);
  }, []);

  if (!show) return null;

  const isIOS = /iPhone|iPad|iPod/i.test(navigator.userAgent);

  const steps = isIOS
    ? (ko
        ? ["Safari 브라우저로 열기", "하단 공유 버튼(□↑) 탭", "'홈 화면에 추가' 선택"]
        : ["Open in Safari browser", "Tap the Share button (□↑)", "Select 'Add to Home Screen'"])
    : (ko
        ? ["Chrome 브라우저로 열기", "오른쪽 상단 ⋮ 메뉴 탭", "'홈 화면에 추가' 선택"]
        : ["Open in Chrome browser", "Tap ⋮ menu (top right)", "Select 'Add to Home Screen'"]);

  return (
    <div style={{
      position:"fixed", bottom: "calc(72px + env(safe-area-inset-bottom,0px) + 8px)",
      left:12, right:12, zIndex:300,
      background:"#1a2535",
      borderRadius:16,
      boxShadow:"0 8px 32px rgba(0,0,0,0.4)",
      border:"1px solid rgba(201,162,39,0.3)",
      overflow:"hidden",
      animation:"slideUp 0.35s cubic-bezier(0.34,1.56,0.64,1)"
    }}>
      <style>{`@keyframes slideUp{from{transform:translateY(100px);opacity:0}to{transform:translateY(0);opacity:1}}`}</style>

      {/* 헤더 바 */}
      <div
        onClick={() => setExpanded(v => !v)}
        style={{ padding:"12px 14px", display:"flex", alignItems:"center", gap:10, cursor:"pointer" }}>
        <span style={{ fontSize:22 }}>📱</span>
        <div style={{ flex:1 }}>
          <div style={{ fontFamily:"Manrope,sans-serif", fontWeight:800, fontSize:13, color:"#ECFDF5" }}>
            {ko ? "홈 화면에 추가하면 앱처럼 쓸 수 있어요" : "Add to home screen for app-like experience"}
          </div>
          <div style={{ fontFamily:"Manrope,sans-serif", fontSize:10.5, color:"rgba(236,253,245,0.5)" }}>
            {ko ? "무료 · 설치 3단계" : "Free · 3 simple steps"}
          </div>
        </div>
        <span style={{ color:"#C9A227", fontSize:18, fontWeight:700 }}>{expanded ? "∨" : "∧"}</span>
        <button
          onClick={(e) => { e.stopPropagation(); localStorage.setItem("hg_pwa_dismissed","1"); setShow(false); }}
          style={{ background:"transparent", border:"none", color:"rgba(236,253,245,0.4)", fontSize:18, cursor:"pointer", padding:"0 4px", lineHeight:1 }}>×</button>
      </div>

      {/* 확장 단계 */}
      {expanded && (
        <div style={{ padding:"0 14px 14px", borderTop:"1px solid rgba(255,255,255,0.07)" }}>
          <div style={{ display:"flex", gap:8, marginTop:10 }}>
            {steps.map((s, i) => (
              <div key={i} style={{ flex:1, background:"rgba(255,255,255,0.05)", borderRadius:10, padding:"10px 8px", textAlign:"center" }}>
                <div style={{ width:22, height:22, borderRadius:"50%", background:"#C9A227", color:"#000", fontFamily:"Manrope,sans-serif", fontWeight:900, fontSize:12, display:"flex", alignItems:"center", justifyContent:"center", margin:"0 auto 6px" }}>{i+1}</div>
                <div style={{ fontFamily:"Manrope,sans-serif", fontSize:10.5, color:"rgba(236,253,245,0.75)", lineHeight:1.4 }}>{s}</div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

/* ─────────────────────────────────────────
   HOME: 플라이휠 소셜 프루프 바 (쿠팡 원리 ①)
   — "312개 교회 · 68개 도시" 숫자가 신뢰를 만든다
───────────────────────────────────────── */
function HebronFlywheelBar({ lang }: { lang: string }) {
  const stats = [
    { emoji: "🌍", value: "68", label: lang === "ko" ? "개 도시" : "Cities" },
    { emoji: "🤝", value: "4", label: lang === "ko" ? "기관 파트너" : "Partners" },
    { emoji: "🌐", value: "2", label: lang === "ko" ? "개 언어" : "Languages" },
  ];
  return (
    <div style={{ background: "#fff", borderBottom: "1px solid rgba(0,0,0,0.07)" }}>
      <div style={{ display: "flex", overflowX: "auto", scrollbarWidth: "none", padding: "0 6px" }}
        className="[&::-webkit-scrollbar]:hidden">
        {stats.map((s, i) => (
          <div key={i} style={{
            flexShrink: 0, display: "flex", alignItems: "center", gap: 6,
            padding: "10px 16px",
            borderRight: i < stats.length - 1 ? "1px solid rgba(0,0,0,0.06)" : "none",
          }}>
            <span style={{ fontSize: 14 }}>{s.emoji}</span>
            <div>
              <span style={{ fontFamily: "-apple-system,'SF Pro Display',Manrope,sans-serif", fontWeight: 800, fontSize: 14, color: "#1C1C1E", letterSpacing: "-0.3px" }}>{s.value}</span>
              <span style={{ fontFamily: "-apple-system,'SF Pro Text',Manrope,sans-serif", fontSize: 11, color: "#8E8E93", marginLeft: 3 }}>{s.label}</span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

