/* ── 음성 검색 버튼 — 마이크로 말하면 검색어 자동 입력 ── */
function SearchVoiceButton({ onResult, lang }: { onResult: (text: string) => void; lang: string }) {
  const ko = lang === "ko";
  const [listening, setListening] = useState(false);
  const [supported] = useState(() => {
    if (typeof window === "undefined") return false;
    return !!((window as unknown as {SpeechRecognition?:unknown}).SpeechRecognition
            || (window as unknown as {webkitSpeechRecognition?:unknown}).webkitSpeechRecognition);
  });
  if (!supported) return null;

  const toggle = () => {
    const SR = (window as unknown as {SpeechRecognition?:unknown}).SpeechRecognition
            || (window as unknown as {webkitSpeechRecognition?:unknown}).webkitSpeechRecognition;
    if (!SR) return;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const rec = new (SR as any)();
    rec.lang = ko ? "ko-KR" : "en-US";
    rec.continuous = false;
    rec.interimResults = false;
    rec.onstart  = () => setListening(true);
    rec.onend    = () => setListening(false);
    rec.onresult = (e: { results: SpeechRecognitionResultList }) => {
      const text = e.results[0]?.[0]?.transcript || "";
      if (text) onResult(text);
    };
    rec.onerror  = () => setListening(false);
    rec.start();
  };

  return (
    <button
      onClick={toggle}
      title={ko ? "음성으로 검색" : "Voice search"}
      style={{
        width: 36, height: 36, borderRadius: "50%", border: "none",
        background: listening ? "rgba(255,59,48,0.12)" : "rgba(120,120,128,0.12)",
        display: "flex", alignItems: "center", justifyContent: "center",
        cursor: "pointer", flexShrink: 0, transition: "all 0.18s",
        boxShadow: listening ? "0 0 12px rgba(255,59,48,0.3)" : "none",
      }}>
      {listening
        ? <svg width="16" height="16" viewBox="0 0 24 24" fill="#FF3B30"><circle cx="12" cy="12" r="6"/></svg>
        : <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#8E8E93" strokeWidth="2" strokeLinecap="round">
            <path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/>
            <path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="23"/>
            <line x1="8" y1="23" x2="16" y2="23"/>
          </svg>
      }
    </button>
  );
}

function ChatShareModal({ onClose, lang, activeNav = 0 }: { onClose: () => void; lang: string; activeNav?: number }) {
  const shareCity    = useCityConfig();
  const appUrl       = `https://hebronguide.com/${shareCity.slug}/`;
  const shareIdentity = DIASPORA_IDENTITY[shareCity.slug] ?? { flag: "🌍", ko: "현지 한인", en: "Korean Diaspora" };
  const SHARE_CTX    = getShareContexts(shareCity.nameKo, shareCity.nameEn, shareCity.slug, shareIdentity);
  const ctx          = SHARE_CTX[activeNav] ?? SHARE_CTX[0];
  const bodyText     = lang === "ko" ? ctx.textKo : ctx.textEn;
  const fullMsg      = `${bodyText}\n\n📱 HebronGuide ${shareCity.nameKo} — hebronguide.com/${shareCity.slug}\n${ctx.tags}`;

  const [copied, setCopied] = useState(false);

  const copy = () => {
    navigator.clipboard?.writeText(fullMsg + "\n" + appUrl).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2500);
    });
  };

  const nativeShare = () => {
    if (navigator.share) {
      navigator.share({ title: `HebronGuide ${shareCity.nameKo} — ${lang === "ko" ? ctx.labelKo : ctx.labelEn}`, text: fullMsg, url: appUrl }).catch(() => {});
    } else {
      copy();
    }
    onClose();
  };

  const encoded   = encodeURIComponent(fullMsg + "\n" + appUrl);
  const encodedUrl = encodeURIComponent(appUrl);

  // Instagram/TikTok: 텍스트 복사 후 앱 열기 (웹 직접 공유 불가)
  const openWithCopy = (appUrl2: string) => {
    navigator.clipboard?.writeText(fullMsg + "\n" + appUrl).then(() => {
      window.open(appUrl2, "_blank");
    }).catch(() => {
      window.open(appUrl2, "_blank");
    });
  };

  // SNS 플랫폼 목록 — 실제 브랜드 공식 SVG 로고 사용
  // 법적 근거: 공유 버튼 용도(Nominative Use)는 각 플랫폼 Brand Guidelines이 명시적으로 허용
  // KakaoTalk: https://developers.kakao.com/docs/latest/ko/reference/design-guide
  // Meta(FB/IG/WA): https://about.meta.com/brand/resources/
  // X: https://about.twitter.com/en/who-we-are/brand-toolkit
  const platforms: { label: string; sub: string; bg: string; icon: React.ReactNode; action?: () => void; href?: string }[] = [
    // 1행
    { label: "카카오톡", sub: lang === "ko" ? "한국인 필수" : "Korean #1", bg: "#FAE100",
      icon: (
        /* KakaoTalk 공식 로고 — 노란 배경 위 다크브라운 말풍선 */
        <svg viewBox="0 0 60 60" width="28" height="28">
          {/* 말풍선 본체 */}
          <ellipse cx="30" cy="25" rx="22" ry="17" fill="#3B1E1C"/>
          {/* 말풍선 꼬리 */}
          <polygon points="20,39 14,52 30,43" fill="#3B1E1C"/>
        </svg>
      ),
      action: () => {
        const kakaoUrl = `kakaotalk://msg/send?text=${encoded}`;
        const fallback = `https://story.kakao.com/share?url=${encodedUrl}&text=${encodeURIComponent(fullMsg)}`;
        try { window.location.href = kakaoUrl; setTimeout(() => window.open(fallback, "_blank"), 1500); }
        catch { window.open(fallback, "_blank"); }
      }
    },
    { label: "WhatsApp", sub: lang === "ko" ? "글로벌 20억+" : "2B+ users", bg: "#25D366",
      icon: (
        /* WhatsApp 공식 로고 — 채팅 버블 + 전화기 */
        <svg viewBox="0 0 175.216 175.552" width="28" height="28" fill="white">
          <path d="M87.6 0C39.3 0 0 39.3 0 87.6c0 15.3 4 29.7 10.9 42.2L0 175.6l47.2-11c12 6.4 25.7 10 40.4 10 48.3 0 87.6-39.3 87.6-87.6S135.9 0 87.6 0zm0 159.8c-13.5 0-26.1-3.8-36.8-10.4l-2.7-1.6-27.9 7.3 7.5-27.2-1.7-2.8C19.1 114.5 15 101.5 15 87.6 15 47.5 47.5 15 87.6 15s72.6 32.5 72.6 72.6-32.5 72.2-72.6 72.2z"/>
          <path d="M127.3 105.7c-2-1-11.9-5.8-13.7-6.5-1.8-.7-3.2-1-4.5.9-1.3 2-5.1 6.5-6.2 7.8-1.1 1.4-2.3 1.5-4.2.5-2-.9-8.3-3.1-15.8-9.8-5.8-5.2-9.8-11.7-10.9-13.7-1.1-2 0-3 .9-4 .8-.9 2-2.3 3-3.4.9-1.1 1.3-2 2-3.3.7-1.4.3-2.5-.1-3.4-.5-1-4.5-10.8-6.1-14.8-1.6-3.9-3.3-3.4-4.5-3.4-1.2-.1-2.5-.1-3.8-.1-1.3 0-3.5.5-5.3 2.5-1.8 2-7 6.8-7 16.6 0 9.8 7.2 19.3 8.2 20.7 1 1.3 14.1 21.5 34.2 30.2 4.8 2.1 8.5 3.3 11.4 4.2 4.8 1.5 9.2 1.3 12.6.8 3.8-.6 11.9-4.9 13.6-9.6 1.7-4.7 1.7-8.7 1.2-9.6-.5-1-1.9-1.5-3.9-2.5z"/>
        </svg>
      ),
      href: `https://wa.me/?text=${encoded}` },
    { label: "Instagram", sub: lang === "ko" ? "스토리에 붙여넣기" : "Copy → Stories", bg: "linear-gradient(135deg,#405DE6,#833AB4,#C13584,#E1306C,#F77737,#FCAF45)",
      icon: (
        /* Instagram 공식 로고 */
        <svg viewBox="0 0 24 24" width="27" height="27" fill="white">
          <path d="M12 2.163c3.204 0 3.584.012 4.85.07 3.252.148 4.771 1.691 4.919 4.919.058 1.265.069 1.645.069 4.849 0 3.205-.012 3.584-.069 4.849-.149 3.225-1.664 4.771-4.919 4.919-1.266.058-1.644.07-4.85.07-3.204 0-3.584-.012-4.849-.07-3.26-.149-4.771-1.699-4.919-4.92-.058-1.265-.07-1.644-.07-4.849 0-3.204.013-3.583.07-4.849.149-3.227 1.664-4.771 4.919-4.919 1.266-.057 1.645-.069 4.849-.069zm0-2.163c-3.259 0-3.667.014-4.947.072-4.358.2-6.78 2.618-6.98 6.98-.059 1.281-.073 1.689-.073 4.948 0 3.259.014 3.668.072 4.948.2 4.358 2.618 6.78 6.98 6.98 1.281.058 1.689.072 4.948.072 3.259 0 3.668-.014 4.948-.072 4.354-.2 6.782-2.618 6.979-6.98.059-1.28.073-1.689.073-4.948 0-3.259-.014-3.667-.072-4.947-.196-4.354-2.617-6.78-6.979-6.98-1.281-.059-1.69-.073-4.949-.073zm0 5.838c-3.403 0-6.162 2.759-6.162 6.162s2.759 6.163 6.162 6.163 6.162-2.759 6.162-6.163c0-3.403-2.759-6.162-6.162-6.162zm0 10.162c-2.209 0-4-1.79-4-4 0-2.209 1.791-4 4-4s4 1.791 4 4c0 2.21-1.791 4-4 4zm6.406-11.845c-.796 0-1.441.645-1.441 1.44s.645 1.44 1.441 1.44c.795 0 1.439-.645 1.439-1.44s-.644-1.44-1.439-1.44z"/>
        </svg>
      ),
      action: () => openWithCopy("https://www.instagram.com/") },
    { label: "TikTok", sub: lang === "ko" ? "복사 후 앱 열기" : "Copy → paste in app", bg: "#010101",
      icon: (
        /* TikTok 공식 로고 */
        <svg viewBox="0 0 24 24" width="27" height="27" fill="white">
          <path d="M19.59 6.69a4.83 4.83 0 01-3.77-4.25V2h-3.45v13.67a2.89 2.89 0 01-2.88 2.5 2.89 2.89 0 01-2.89-2.89 2.89 2.89 0 012.89-2.89c.28 0 .54.04.79.1V9.01a6.33 6.33 0 00-.79-.05 6.34 6.34 0 00-6.34 6.34 6.34 6.34 0 006.34 6.34 6.34 6.34 0 006.33-6.34V8.69a8.18 8.18 0 004.79 1.52V6.76a4.85 4.85 0 01-1.02-.07z"/>
        </svg>
      ),
      action: () => openWithCopy("https://www.tiktok.com/") },
    // 2행
    { label: "Facebook", sub: "", bg: "#1877F2",
      icon: (
        /* Facebook 공식 'f' 로고 */
        <svg viewBox="0 0 24 24" width="27" height="27" fill="white">
          <path d="M24 12.073c0-6.627-5.373-12-12-12s-12 5.373-12 12c0 5.99 4.388 10.954 10.125 11.854v-8.385H7.078v-3.47h3.047V9.43c0-3.007 1.792-4.669 4.533-4.669 1.312 0 2.686.235 2.686.235v2.953H15.83c-1.491 0-1.956.925-1.956 1.874v2.25h3.328l-.532 3.47h-2.796v8.385C19.612 23.027 24 18.062 24 12.073z"/>
        </svg>
      ),
      href: `https://www.facebook.com/sharer/sharer.php?u=${encodedUrl}&quote=${encodeURIComponent(fullMsg)}` },
    { label: "X (Twitter)", sub: "", bg: "#000000",
      icon: (
        /* X(Twitter) 공식 로고 */
        <svg viewBox="0 0 24 24" width="27" height="27" fill="white">
          <path d="M18.244 2.25h3.308l-7.227 8.26 8.502 11.24H16.17l-5.214-6.817L4.99 21.75H1.68l7.73-8.835L1.254 2.25H8.08l4.713 6.231zm-1.161 17.52h1.833L7.084 4.126H5.117z"/>
        </svg>
      ),
      href: `https://twitter.com/intent/tweet?text=${encodeURIComponent(bodyText + "\n" + ctx.tags)}&url=${encodedUrl}` },
    { label: lang === "ko" ? "이메일" : "Email", sub: "Gmail · Outlook", bg: "#EA4335",
      icon: (
        /* Gmail/Email 아이콘 */
        <svg viewBox="0 0 24 24" width="27" height="27" fill="white">
          <path d="M24 5.457v13.909c0 .904-.732 1.636-1.636 1.636h-3.819V11.73L12 16.64l-6.545-4.91v9.273H1.636A1.636 1.636 0 010 19.366V5.457c0-2.023 2.309-3.178 3.927-1.964L5.455 4.64 12 9.548l6.545-4.91 1.528-1.145C21.69 2.28 24 3.434 24 5.457z"/>
        </svg>
      ),
      href: `mailto:?subject=HebronGuide&body=${encodeURIComponent(fullMsg + "\n\n" + appUrl)}` },
    { label: lang === "ko" ? "링크 복사" : "Copy Link", sub: lang === "ko" ? "클립보드" : "Clipboard", bg: "#475569",
      icon: (
        <svg viewBox="0 0 28 28" width="26" height="26" fill="none" stroke="white" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
          <path d="M11.5 16.5H8a5 5 0 010-10h4.5m1 7H20a5 5 0 000-10h-4.5M10 14h8"/>
        </svg>
      ),
      action: copy },
  ];

  return (
    <div style={{ position:"fixed", inset:0, zIndex:300,
      background:"rgba(0,0,0,0.4)", backdropFilter:"blur(16px) saturate(180%)",
      display:"flex", alignItems:"flex-end" }} onClick={onClose}>
      <div style={{ width:"100%", maxWidth:430, margin:"0 auto",
        background:"rgba(255,255,255,0.97)", backdropFilter:"saturate(180%) blur(20px)",
        borderRadius:"22px 22px 0 0", paddingBottom:"env(safe-area-inset-bottom,20px)",
        boxShadow:"0 -2px 0 rgba(0,0,0,0.06), 0 -20px 60px rgba(0,0,0,0.15)" }}
        onClick={e => e.stopPropagation()}>

        {/* ── Apple 핸들 바 ── */}
        <div style={{ display:"flex", justifyContent:"center", padding:"10px 0 0" }}>
          <div style={{ width:36, height:4, borderRadius:2, background:"rgba(0,0,0,0.15)" }} />
        </div>

        {/* ── 헤더 ── */}
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"14px 20px 0" }}>
          <div>
            <div style={{ fontFamily:"-apple-system,'Noto Sans KR',sans-serif",
              fontWeight:700, fontSize:17, color:"#1C1C1E", letterSpacing:"-0.3px" }}>
              {lang === "ko" ? "공유하기" : "Share"}
            </div>
            <div style={{ fontFamily:"-apple-system,sans-serif", fontSize:12, color:"#8E8E93", marginTop:2 }}>
              {ctx.emoji} {lang === "ko" ? ctx.labelKo : ctx.labelEn}
            </div>
          </div>
          <button onClick={onClose} style={{ border:"none",
            background:"rgba(120,120,128,0.12)", borderRadius:"50%",
            width:30, height:30, fontSize:14, cursor:"pointer", color:"#8E8E93",
            display:"flex", alignItems:"center", justifyContent:"center" }}>✕</button>
        </div>

        {/* ── 공유 미리보기 카드 ── */}
        <div style={{ margin:"12px 16px 0", background:"rgba(118,118,128,0.05)",
          border:"1px solid rgba(118,118,128,0.12)", borderRadius:14, padding:"12px 14px 10px" }}>
          <div style={{ fontFamily:"-apple-system,'Noto Sans KR',sans-serif",
            fontSize:12, color:"#3C3C43", lineHeight:1.65, whiteSpace:"pre-line", opacity:0.8 }}>
            {bodyText}
          </div>
          <div style={{ marginTop: 8, paddingTop: 8, borderTop: "1px solid #E2E8F0", display: "flex", alignItems: "center", gap: 6 }}>
            <div style={{ width: 20, height: 20, borderRadius: 5, background: "#1B2A4A", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 11 }}>🧭</div>
            <div style={{ fontSize: 11, fontWeight: 700, color: "#1B2A4A" }}>HebronGuide</div>
            <div style={{ fontSize: 11, color: "#94A3B8" }}>hebronguide.com/seattle</div>
          </div>
          <div style={{ marginTop: 4, fontSize: 10, color: "#94A3B8" }}>{ctx.tags}</div>
        </div>

        {/* ── SNS 플랫폼 그리드 (4열 아이콘형) ── */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 6, padding: "14px 16px 6px" }}>
          {platforms.map((p, i) => {
            const isLast = i === platforms.length - 1;
            const isInstagram = i === 2;
            const isTikTok = i === 3;
            const inner = (
              <>
                {/* 브랜드 컬러 배경 + SVG 아이콘 */}
                <div style={{
                  width: 52, height: 52, borderRadius: 16,
                  background: p.bg,
                  boxShadow: "0 2px 10px rgba(0,0,0,0.18)",
                  display: "flex", alignItems: "center", justifyContent: "center",
                  marginBottom: 5, flexShrink: 0,
                }}>
                  {isLast && copied
                    ? <svg viewBox="0 0 24 24" width="26" height="26"><polyline points="4 12 9 17 20 7" stroke="white" strokeWidth="2.5" fill="none" strokeLinecap="round" strokeLinejoin="round"/></svg>
                    : p.icon}
                </div>
                <div style={{ fontFamily: "Manrope,sans-serif", fontWeight: 700, fontSize: 10, color: "#1B2A4A", textAlign: "center", lineHeight: 1.2 }}>
                  {isLast && copied ? (lang === "ko" ? "복사됨!" : "Copied!") : p.label}
                </div>
                {(isInstagram || isTikTok) && (
                  <div style={{ fontSize: 8, color: "#F59E0B", fontWeight: 700, textAlign: "center", marginTop: 1 }}>
                    {lang === "ko" ? "복사→붙여넣기" : "copy→paste"}
                  </div>
                )}
              </>
            );
            return p.action ? (
              <button key={i} onClick={p.action}
                style={{ display: "flex", flexDirection: "column", alignItems: "center", padding: "6px 2px", border: "none", background: "transparent", cursor: "pointer" }}>
                {inner}
              </button>
            ) : (
              <a key={i} href={(p as any).href} target="_blank" rel="noopener noreferrer"
                style={{ display: "flex", flexDirection: "column", alignItems: "center", padding: "6px 2px", textDecoration: "none" }}>
                {inner}
              </a>
            );
          })}
        </div>

        {/* ── 폰 기본 공유 큰 버튼 (카카오·문자·이메일 등 전부) ── */}
        <div style={{ padding: "8px 16px 6px" }}>
          <button onClick={nativeShare} style={{ width: "100%", border: "none", borderRadius: 14, background: "linear-gradient(135deg,#F2994A,#F59E0B)", padding: "13px 16px", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
            <span style={{ fontSize: 18 }}>📤</span>
            <span style={{ fontFamily: "Manrope,sans-serif", fontWeight: 800, fontSize: 13, color: "#fff" }}>
              {lang === "ko" ? "폰 공유 시트 열기 (카카오·문자·이메일…)" : "Open share sheet (KakaoTalk, SMS, Mail…)"}
            </span>
          </button>
        </div>

        {/* ── 하단 안내 ── */}
        <div style={{ padding: "6px 16px 14px", textAlign: "center" }}>
          <div style={{ fontSize: 10, color: "#CBD5E1" }}>
            💡 {lang === "ko" ? "공유 시 HebronGuide 링크가 자동으로 포함됩니다" : "HebronGuide link is automatically included in every share"}
          </div>
        </div>
      </div>
    </div>
  );
}


/* ─────────────────────────────────────────
   더보기 시트 항목
───────────────────────────────────────── */
const MORE_SECTIONS = [
  /* ── 1행: 메인 섹션 ── */
  { icon: Church,       labelKo: "교회",      labelEn: "Church",       tab: 2,  subTab: 0, color: "#7C3AED" },
  { icon: Map,          labelKo: "관광",      labelEn: "Tourism",      tab: 4,  subTab: 0, color: "#0EA5E9" },
  { icon: Briefcase,    labelKo: "취업",      labelEn: "Jobs",         tab: 6,  subTab: 0, color: "#059669" },
  { icon: GraduationCap,labelKo: "교육",      labelEn: "Schools",      tab: 7,  subTab: 0, color: "#F59E0B" },
  { icon: DollarSign,   labelKo: "생활비",    labelEn: "Costs",        tab: 8,  subTab: 0, color: "#8B5CF6" },
  /* ── 2행: 빠른 접근 ── */
  { icon: Building2,    labelKo: "한인 업소", labelEn: "Business",     tab: 12, subTab: 0, color: "#4F46E5" },
  { icon: FileText,     labelKo: "비자·이민", labelEn: "Visa",         tab: 1,  subTab: 7, color: "#6366F1" },
  { icon: Receipt,      labelKo: "세금신고",  labelEn: "Taxes",        tab: 8,  subTab: 4, color: "#F97316" },
  { icon: Scale,        labelKo: "법률상담",  labelEn: "Legal",        tab: 5,  subTab: 5, color: "#64748B" },
  { icon: BookOpen,     labelKo: "한국학교",  labelEn: "K-School",     tab: 7,  subTab: 5, color: "#BE185D" },
];

/* ─────────────────────────────────────────
   하단 네비 5개 탭 — 모듈 레벨 (BottomNav + DesktopSidebar 공유)
───────────────────────────────────────── */
const NAV_ITEMS = [
  { id: "home",    tab: 0,  icon: Home,       labelKo: "홈",    labelEn: "Home"    },
  { id: "settle",  tab: 1,  icon: Users,      labelKo: "정착",  labelEn: "Settle"  },
  { id: "explore", tab: 4,  icon: Map,        labelKo: "탐방",  labelEn: "Explore" },
  { id: "help",    tab: 5,  icon: HeartPulse, labelKo: "도움",  labelEn: "Help"    },
  { id: "more",    tab: -1, icon: Grid,       labelKo: "더보기", labelEn: "More"   },
] as const;

interface BottomNavProps {
  activeIndex: number;
  onChange: (i: number, subTab?: number) => void;
  onSearchToggle: () => void;
  onShareToggle: () => void;
  onTranslateToggle: () => void;
}
function BottomNav({ activeIndex, onChange, onSearchToggle, onShareToggle, onTranslateToggle }: BottomNavProps) {
  const { lang } = useI18n();
  const [showMore, setShowMore] = useState(false);

  const handleNavClick = (item: typeof NAV_ITEMS[0]) => {
    if (item.id === "more") { setShowMore(prev => !prev); return; }
    setShowMore(false);
    onChange(item.tab);
  };

  const handleMoreSection = (tab: number, subTab?: number) => {
    onChange(tab, subTab);
    setShowMore(false);
  };

  const ACCENT = "#F2994A";

  return (
    <>
      {/* 더보기 시트 — 반투명 오버레이 */}
      {showMore && (
        <div
          className="fixed inset-0 z-40 lg:hidden"
          style={{ background: "rgba(0,0,0,0.4)", backdropFilter: "blur(2px)" }}
          onClick={() => setShowMore(false)}
        />
      )}

      {/* 더보기 바텀 시트 */}
      {showMore && (
        <div
          className="fixed z-50 lg:hidden"
          style={{
            bottom: "calc(56px + env(safe-area-inset-bottom, 0px))",
            left: "50%", transform: "translateX(-50%)",
            width: "100%", maxWidth: 430,
            background: "#fff",
            borderRadius: "20px 20px 0 0",
            boxShadow: "0 -4px 32px rgba(0,0,0,0.18)",
            padding: "16px 16px 12px",
          }}
        >
          {/* 핸들 */}
          <div style={{ width: 36, height: 4, borderRadius: 2, background: "#E5E7EB", margin: "0 auto 16px" }} />

          {/* 섹션 버튼 그리드 — 2행 */}
          {[MORE_SECTIONS.slice(0, 5), MORE_SECTIONS.slice(5)].map((row, rowIdx) => (
            <div key={rowIdx} style={{ display: "grid", gridTemplateColumns: "repeat(5, 1fr)", gap: 8, marginBottom: rowIdx === 0 ? 8 : 16 }}>
              {rowIdx === 1 && (
                /* 2행 라벨 */
                <div style={{ gridColumn: "1 / -1", marginBottom: 2, paddingLeft: 2 }}>
                  <span style={{ fontSize: 10, fontWeight: 700, color: "#94A3B8", letterSpacing: "0.5px",
                    fontFamily: "Manrope, sans-serif" }}>
                    {lang === "ko" ? "⚡ 빠른 접근" : "⚡ QUICK ACCESS"}
                  </span>
                </div>
              )}
              {row.map((s) => {
                const isActive = activeIndex === s.tab;
                const IconComp = s.icon;
                return (
                  <button
                    key={`${s.tab}-${s.subTab}`}
                    onClick={() => handleMoreSection(s.tab, s.subTab)}
                    style={{
                      display: "flex", flexDirection: "column", alignItems: "center", gap: 6,
                      padding: "10px 4px 8px", borderRadius: 14, border: "none", cursor: "pointer",
                      background: isActive ? `${s.color}15` : "#F8FAFC",
                      outline: isActive ? `1.5px solid ${s.color}40` : "none",
                      transition: "all 0.15s ease",
                    }}
                  >
                    <div style={{
                      width: 38, height: 38, borderRadius: 12,
                      background: isActive ? s.color : `${s.color}18`,
                      display: "flex", alignItems: "center", justifyContent: "center",
                    }}>
                      <IconComp size={20} color={isActive ? "#fff" : s.color} strokeWidth={1.8} />
                    </div>
                    <span style={{
                      fontSize: 10, fontWeight: 600,
                      color: isActive ? s.color : "#374151",
                      fontFamily: "-apple-system, 'Noto Sans KR', sans-serif",
                      textAlign: "center", lineHeight: 1.2,
                    }}>
                      {lang === "ko" ? s.labelKo : s.labelEn}
                    </span>
                  </button>
                );
              })}
            </div>
          ))}

          {/* 구분선 */}
          <div style={{ height: 1, background: "#F1F5F9", marginBottom: 12 }} />

          {/* 유틸 버튼 */}
          <div style={{ display: "flex", gap: 8 }}>
            {[
              { icon: Search,       labelKo: "검색",       labelEn: "Search",    action: () => { onSearchToggle(); setShowMore(false); } },
              { icon: Globe,        labelKo: "통역",       labelEn: "Translate", action: () => { onTranslateToggle(); setShowMore(false); } },
              { icon: Share2,       labelKo: "공유",       labelEn: "Share",     action: () => { onShareToggle(); setShowMore(false); } },
              { icon: RefreshCw,    labelKo: "최신 정보",  labelEn: "Refresh",   action: () => {
                  setShowMore(false);
                  // 환대 어조: 짧은 토스트 표시 후 캐시 비우고 새로고침
                  const helper = (window as unknown as { __hebronRefreshNow?: () => Promise<void> }).__hebronRefreshNow;
                  if (typeof helper === 'function') {
                    helper();
                  } else {
                    // fallback — 헬퍼 미등록 환경
                    window.location.reload();
                  }
                } },
            ].map((u, i) => {
              const IconComp = u.icon;
              return (
                <button
                  key={i}
                  onClick={u.action}
                  style={{
                    flex: 1, display: "flex", flexDirection: "column", alignItems: "center",
                    gap: 5, padding: "10px 4px", borderRadius: 12, border: "none",
                    background: "#F8FAFC", cursor: "pointer",
                  }}
                >
                  <IconComp size={20} color="#6B7280" strokeWidth={1.8} />
                  <span style={{ fontSize: 10, fontWeight: 600, color: "#6B7280",
                    fontFamily: "-apple-system, 'Noto Sans KR', sans-serif" }}>
                    {lang === "ko" ? u.labelKo : u.labelEn}
                  </span>
                </button>
              );
            })}
          </div>

          {/* 파트너 비즈니스 — 광고·파트너 신청 문의 */}
          <a href="/ad-request.html" target="_blank" rel="noopener noreferrer"
            onClick={() => setShowMore(false)}
            style={{
              display: "flex", alignItems: "center", gap: 10,
              marginTop: 12, padding: "11px 14px",
              background: "linear-gradient(135deg, rgba(201,162,39,0.12), rgba(110,231,183,0.08))",
              border: "1px solid rgba(201,162,39,0.3)", borderRadius: 12,
              textDecoration: "none",
            }}>
            {/* 아이콘 */}
            <div style={{ width: 36, height: 36, borderRadius: 10, background: "rgba(201,162,39,0.15)", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, fontSize: 18 }}>
              🤝
            </div>
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: 11.5, fontWeight: 800, color: "#92400E", letterSpacing: "0.1px", marginBottom: 2, fontFamily: "Manrope, sans-serif" }}>
                {lang === "ko" ? "파트너 비즈니스" : "Partner Business"}
              </div>
              <div style={{ fontSize: 10.5, color: "#C9A227", fontWeight: 700, fontFamily: "Manrope, sans-serif" }}>
                {lang === "ko" ? "광고, 파트너 신청 문의 →" : "Ad & Partnership Inquiry →"}
              </div>
            </div>
            <div style={{ fontSize: 16, color: "#C9A227", fontWeight: 700 }}>›</div>
          </a>
        </div>
      )}

      {/* 메인 하단 네비 — iPhone safe area 대응 */}
      <nav
        className="fixed bottom-0 z-50 lg:hidden"
        style={{
          paddingBottom: "env(safe-area-inset-bottom, 0px)",
          left: "50%", transform: "translateX(-50%)",
          width: "100%", maxWidth: 430,
          background: "#F9F9F9",
          borderTop: "0.5px solid rgba(0,0,0,0.18)",
          boxShadow: "0 -1px 0 rgba(0,0,0,0.08)",
        }}
      >
        <div style={{ display: "flex", height: 56, alignItems: "stretch" }}>
          {NAV_ITEMS.map((item) => {
            const isActive = item.tab >= 0 ? activeIndex === item.tab : showMore;
            const IconComp = item.icon;
            return (
              <button
                key={item.id}
                onClick={() => handleNavClick(item)}
                style={{
                  flex: 1, display: "flex", flexDirection: "column",
                  alignItems: "center", justifyContent: "center",
                  gap: 4, paddingTop: 8, paddingBottom: 6,
                  border: "none", background: "none", cursor: "pointer",
                  position: "relative", transition: "transform 0.1s ease",
                }}
                onTouchStart={e => (e.currentTarget.style.transform = "scale(0.92)")}
                onTouchEnd={e => (e.currentTarget.style.transform = "scale(1)")}
              >
                {isActive && (
                  <div style={{
                    position: "absolute", top: 0, left: "50%", width: 28, height: 3,
                    borderRadius: 2, background: ACCENT, transform: "translateX(-50%)",
                  }} />
                )}
                <IconComp size={24} color={isActive ? ACCENT : "#8E8E93"} strokeWidth={isActive ? 2.2 : 1.5} />
                <span style={{
                  fontFamily: "-apple-system, BlinkMacSystemFont, 'SF Pro Text', 'Noto Sans KR', sans-serif",
                  fontWeight: isActive ? 700 : 500, fontSize: 10,
                  color: isActive ? ACCENT : "#8E8E93",
                  whiteSpace: "nowrap", letterSpacing: "-0.2px",
                }}>
                  {lang === "ko" ? item.labelKo : item.labelEn}
                </span>
              </button>
            );
          })}
        </div>
      </nav>
    </>
  );
}

