          const internalMatches = q.length > 0
            ? SEARCH_MAP.filter(item => item.keywords.some(kw => kw.replace(/\s/g,"").includes(q) || q.includes(kw.replace(/\s/g,""))))
            : [];
          const citySlugForSearch = useCityConfig?.()?.slug || "seattle";
